css:
.loader {color: var(--loader-color, #0891b2);
  --loader-secondary-color: #22d3ee;
  --loader-bg: #ffffff;
  display: inline-flex;
  gap: 5px;
}.loader:before,.loader:after {content: "";
  width: 25px;
  aspect-ratio: 1;
  box-shadow: 0 0 0 3px inset var(--loader-bg, #ffffff);
  animation: l5 1.5s infinite;
}.loader:before {--s:-1;
}@keyframes l5 {0% {transform: scale(var(--s,1)) translate(0) scale(1)}33% {transform: scale(var(--s,1)) translate(calc(50% + 2.5px)) scale(1)}66% {transform: scale(var(--s,1)) translate(calc(50% + 2.5px)) scale(2)}100% {transform: scale(var(--s,1)) translate(0) scale(1)}}
